    // MARK: - Lookup Functions
    
    /// Get base MSRP for a specific make/model/year
    static func getBaseValue(make: String, model: String, year: Int) -> Int? {
        // Try exact match first
        if let makeData = values[make],
           let modelData = makeData[model],
           let value = modelData[year] {
            return value
        }
        
        // Try fuzzy model match (e.g., "Silverado" matches "Silverado 1500")
        if let makeData = values[make] {
            for (modelName, yearData) in makeData {
                if modelName.lowercased().contains(model.lowercased()) ||
                   model.lowercased().contains(modelName.lowercased()) {
                    if let value = yearData[year] {
                        return value
                    }
                    // Try closest year
                    let sortedYears = yearData.keys.sorted(by: >)
                    if let closestYear = sortedYears.first(where: { $0 <= year }) {
                        return yearData[closestYear]
                    }
                }
            }
        }
        
        return nil
    }
    
    /// Estimate base value when no exact match is found, based on vehicle class
    static func estimateBaseValue(year: Int, bodyClass: String?) -> Int {
        let currentYear = Calendar.current.component(.year, from: Date())
        let baseYear = min(year, currentYear)
        
        // Base values by vehicle class (average new MSRP)
        let classValues: [String: Int] = [
            "sedan": 30000,
            "coupe": 32000,
            "hatchback": 26000,
            "convertible": 38000,
            "wagon": 35000,
            "suv": 42000,
            "crossover": 38000,
            "truck": 45000,
            "pickup": 45000,
            "van": 38000,
            "minivan": 36000,
            "sports": 50000,
            "luxury": 55000,
        ]
        
        // Determine class from body type
        var baseValue = 35000 // Default fallback
        
        if let bodyType = bodyClass?.lowercased() {
            for (classType, value) in classValues {
                if bodyType.contains(classType) {
                    baseValue = value
                    break
                }
            }
        }
        
        // Adjust for year (newer years have higher MSRP due to inflation)
        // Assume ~2% annual increase in MSRP
        let yearDiff = currentYear - baseYear
        let inflationFactor = pow(1.02, Double(yearDiff))
        baseValue = Int(Double(baseValue) / inflationFactor)
        
        return baseValue
    }
    
    /// Get all available years for a make/model
    static func availableYears(make: String, model: String) -> [Int]? {
        guard let makeData = values[make],
              let modelData = makeData[model] else {
            return nil
        }
        return modelData.keys.sorted(by: >)
    }
